function eatenApples(apples, days) {
    const n = apples.length;
    const pq = new PriorityQueue();
    let ans = 0;

    for (let i = 0; i < n || !pq.isEmpty(); ++i) {
        if (i < n && apples[i] > 0) {
            pq.enqueue([i + days[i], apples[i]]);
        }

        while (!pq.isEmpty() && pq.peek()[0] <= i) {
            pq.dequeue();
